const ITEM_PREMIUMS: Record<string, number> = {
  Sword: 100,
  Amulet: 60,
};

const PROCESSING_FEE = 5;
const DEFAULT_PREMIUM = 100;

export function calculatePremium(policy: unknown[]): number {
  if (policy.length === 0) return PROCESSING_FEE;

  const items = policy as PolicyItem[];
  if (items.length === 1) {
    const item = items[0];
    const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
    return basePremium + PROCESSING_FEE;
  }

  return DEFAULT_PREMIUM + PROCESSING_FEE;
}

